arguments.command:
cd /tmp && mkdir -p binlog-parser && cd binlog-parser && cat > BinlogParser.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.415" />
  </ItemGroup>
</Project>
EOF

cat > Program.cs << 'CEOF'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
Console.WriteLine("=== ALL ERRORS ===");
build.VisitAllChildren<Error>(e => {
    Console.WriteLine($"  Project: {e.GetNearestParent<Project>()?.Name ?? "N/A"}");
    Console.WriteLine($"  File: {e.File}");
    Console.WriteLine($"  Line: {e.LineNumber}");
    Console.WriteLine($"  Code: {e.Code}");
    Console.WriteLine($"  Message: {e.Text}");
    Console.WriteLine();
});

Console.WriteLine("=== ALL WARNINGS ===");
build.VisitAllChildren<Warning>(w => {
    Console.WriteLine($"  Project: {w.GetNearestParent<Project>()?.Name ?? "N/A"}");
    Console.WriteLine($"  Code: {w.Code}");
    Console.WriteLine($"  Message: {w.Text}");
    Console.WriteLine();
});

// Show project structure
Console.WriteLine("=== PROJECT STRUCTURE ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"  Project: {p.Name} - Succeeded: {p.Succeeded}");
});

// Show source files embedded
Console.WriteLine();
Console.WriteLine("=== EMBEDDED SOURCE FILES ===");
build.VisitAllChildren<SourceFile>(sf => {
    Console.WriteLine($"  SourceFile: {sf.Name}");
    Console.WriteLine($"  Content length: {sf.Text?.Length ?? 0}");
    Console.WriteLine($"  First 500 chars: {(sf.Text?.Length > 500 ? sf.Text.Substring(0, 500) : sf.Text)}");
    Console.WriteLine();
});
CEOF
