using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== ERRORS (3 total in Services.csproj) ===");
build.VisitAllChildren<Error>(e => {
    var proj = e.GetNearestParent<Project>();
    Console.WriteLine($"[{e.Code}] {proj?.Name}: {e.File}({e.LineNumber}): {e.Text}");
});
Console.WriteLine();

// Find the source file content from the import/embedded files 
Console.WriteLine("=== LOOKING FOR EMBEDDED FILES ===");
void WalkTree(BaseNode node, int depth = 0) {
    var indent = new string(' ', depth * 2);
    var typeName = node.GetType().Name;

    if (node is SourceFile sf) {
        Console.WriteLine($"{indent}[SourceFile] {sf.Name}");
    }
    else if (typeName == "Import" || typeName.Contains("Source") || typeName.Contains("File")) {
        Console.WriteLine($"{indent}[{typeName}] {node}");
    }

    if (node is TreeNode tn) {
        foreach (var child in tn.Children) {
            if (child is BaseNode bn)
                WalkTree(bn, depth + 1);
        }
    }
}

// Try to get source files from imports
Console.WriteLine("=== IMPORTS ===");
build.VisitAllChildren<Import>(import => {
    if (import.Name != null && (import.Name.Contains("Models.cs") || import.Name.Contains("UserService.cs") || import.Name.Contains("Program.cs"))) {
        Console.WriteLine($"Import: {import.Name}");
        Console.WriteLine($"  ProjectFilePath: {import.ProjectFilePath}");
        Console.WriteLine($"  ImportedProjectFilePath: {import.ImportedProjectFilePath}");
    }
});

// Try SourceFilesProjection
Console.WriteLine();
Console.WriteLine("=== ALL NODE TYPES ===");
var typeCount = new Dictionary<string, int>();
build.VisitAllChildren<BaseNode>(n => {
    var t = n.GetType().Name;
    typeCount.TryGetValue(t, out var c);
    typeCount[t] = c + 1;
});
foreach (var kv in typeCount.OrderByDescending(x => x.Value))
    Console.WriteLine($"  {kv.Key}: {kv.Value}");

// Find compile items 
Console.WriteLine();
Console.WriteLine("=== COMPILE ITEMS ===");
build.VisitAllChildren<Item>(item => {
    if (item.Name == "Compile") {
        var proj = item.GetNearestParent<Project>();
        Console.WriteLine($"  {proj?.Name}: {item.Text}");
    }
});
