    sfCount++;
    Console.WriteLine($"SourceFile #{sfCount}: {sf}");
    Console.WriteLine($"  FilePath: {sf.FilePath}");
});
Console.WriteLine($"Total SourceFile nodes: {sfCount}");

// Try to find the embedded source content via the archives
