if (build is TreeNode btn) {
    foreach (var child in btn.Children) {
        if (child is BaseNode bn) {
            Console.WriteLine($"  [{bn.GetType().Name}] {bn}");
            if (bn is TreeNode tn2) {
                foreach (var grandchild in tn2.Children) {
                    if (grandchild is BaseNode gc) {
                        var gctype = gc.GetType().Name;
                        if (gctype.Contains("Source") || gctype.Contains("Archive") || gctype.Contains("File"))
                            Console.WriteLine($"    [{gctype}] {gc}");
                    }
                }
            }
        }
    }
}

// Try SourceFiles directly from the log 
Console.WriteLine();
Console.WriteLine("=== LOG SOURCE FILES ===");
var log = build;
var sourceFilesField = log.GetType().GetProperty("SourceFiles");
if (sourceFilesField != null) {
    var sourceFiles = sourceFilesField.GetValue(log);
    Console.WriteLine($"SourceFiles: {sourceFiles}");
}

// Get embedded file content using the API
Console.WriteLine();
Console.WriteLine("=== EMBEDDED FILES FROM BINLOG ===");
var archiveFiles = build.SourceFiles;
if (archiveFiles != null) {
    Console.WriteLine($"Count: {archiveFiles.Count}");
    foreach (var file in archiveFiles) {
        Console.WriteLine($"  {file.Key} ({file.Value?.Length ?? 0} chars)");
        if (file.Key.EndsWith(".cs") && !file.Key.Contains("AssemblyAttributes") && !file.Key.Contains("AssemblyInfo")) {
            Console.WriteLine($"--- CONTENT of {file.Key} ---");
            Console.WriteLine(file.Value);
            Console.WriteLine("--- END ---");
        }
    }
}
