using System.Reflection;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== ERRORS ===");
build.VisitAllChildren<Error>(e => {
    var proj = e.GetNearestParent<Project>();
    Console.WriteLine($"[{e.Code}] {proj?.Name}: {e.File}({e.LineNumber}): {e.Text}");
});
Console.WriteLine();

// List properties of ArchiveFile 
var sfType = typeof(SourceFile);
Console.WriteLine($"SourceFile properties:");
foreach (var p in sfType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  {p.Name}: {p.PropertyType.Name}");

Console.WriteLine($"\nSourceFile fields:");
foreach (var f in sfType.GetFields(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  {f.Name}: {f.FieldType.Name}");

var archType = typeof(ArchiveFile);
Console.WriteLine($"\nArchiveFile properties:");
foreach (var p in archType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  {p.Name}: {p.PropertyType.Name}");

Console.WriteLine($"\nArchiveFile fields:");
foreach (var f in archType.GetFields(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  {f.Name}: {f.FieldType.Name}");

// Access embedded files
Console.WriteLine("\n=== EMBEDDED FILES FROM BINLOG ===");
var sourceFiles = build.SourceFiles;
if (sourceFiles != null) {
    Console.WriteLine($"Count: {sourceFiles.Count}");
    foreach (var file in sourceFiles) {
        // Reflection approach since API changed
        var props = file.GetType().GetProperties(BindingFlags.Public | BindingFlags.Instance);
        var vals = new Dictionary<string, object?>();
        foreach (var p in props) {
            vals[p.Name] = p.GetValue(file);
        }
        var fullPath = vals.ContainsKey("FullPath") ? vals["FullPath"]?.ToString() : null;
        var text = vals.ContainsKey("Text") ? vals["Text"]?.ToString() : null;

        Console.WriteLine($"  {fullPath ?? file.ToString()} ({text?.Length ?? 0} chars)");
        if (fullPath != null && fullPath.EndsWith(".cs") && !fullPath.Contains("AssemblyAttributes") && !fullPath.Contains("AssemblyInfo")) {
            Console.WriteLine($"--- CONTENT of {fullPath} ---");
            Console.WriteLine(text ?? "(no text)");
            Console.WriteLine("--- END ---");
        }
    }
} else {
    Console.WriteLine("No SourceFiles collection found.");
}
