using Microsoft.Build.Logging.StructuredLogger;
using System.Reflection;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Print Services project.assets.json to see NuGet packages
var sourceFiles = build.SourceFiles;
foreach (var file in sourceFiles) {
    var props = file.GetType().GetProperties(BindingFlags.Public | BindingFlags.Instance);
    var fullPath = props.First(p => p.Name == "FullPath").GetValue(file)?.ToString();
    var text = props.First(p => p.Name == "Text").GetValue(file)?.ToString();

    // Show the csproj and assets files
    if (fullPath != null && (fullPath.EndsWith("Services.csproj") || fullPath.EndsWith("Api.csproj") || fullPath.EndsWith("Core.csproj"))) {
        Console.WriteLine($"=== {fullPath} ===");
        Console.WriteLine(text);
        Console.WriteLine();
    }
    if (fullPath != null && fullPath.Contains("Services") && fullPath.Contains("project.assets.json")) {
        Console.WriteLine($"=== {fullPath} (first 2000 chars) ===");
        Console.WriteLine(text?.Substring(0, Math.Min(2000, text?.Length ?? 0)));
        Console.WriteLine();
    }
}

// Check if Api build was skipped / did it produce errors?
Console.WriteLine("=== PROJECT RESULTS ===");
build.VisitAllChildren<Project>(p => {
    // Check for errors in this project
    var errors = new List<string>();
    p.VisitAllChildren<Error>(e => errors.Add(e.Code));
    var messages = new List<string>();
    p.VisitAllChildren<Message>(m => {
        if (m.Text != null && (m.Text.Contains("not build") || m.Text.Contains("skipped") || m.Text.Contains("failed")))
            messages.Add(m.Text);
    });
    Console.WriteLine($"  {p.Name} - errors: [{string.Join(", ", errors)}] messages: [{string.Join("; ", messages.Take(3))}]");
});

// Check for MSB4181 or project dependency failures 
Console.WriteLine();
Console.WriteLine("=== MESSAGES ABOUT DEPENDENT PROJECTS ===");
build.VisitAllChildren<Message>(m => {
    if (m.Text != null && (m.Text.Contains("MSB3202") || m.Text.Contains("MSB4181") || m.Text.Contains("did not build") || m.Text.Contains("project reference")))
        Console.WriteLine($"  {m.Text}");
});
